func (this *MudrexCore) ParseOrderStatus(status any) any {
	var statuses any = map[string]any{
		"open":             "open",
		"created":          "open",
		"new":              "open",
		"pending":          "open",
		"partially_filled": "open",
		"filled":           "closed",
		"completed":        "closed",
		"cancelled":        "canceled",
		"canceled":         "canceled",
		"rejected":         "rejected",
		"expired":          "expired",
	}
	return this.SafeString(statuses, status, status)
}
func (this *MudrexCore) ParseOrder(order any, optionalArgs ...any) any {
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var oms any = this.SafeString(order, "symbol")
	market = this.SafeMarket(oms, market)
	var oid any = this.SafeString2(order, "order_id", "id")
	var rawSide any = this.SafeStringUpper(order, "order_type")
	var side any = nil
	if IsTrue(IsEqual(rawSide, "LONG")) {
		side = "buy"
	} else if IsTrue(IsEqual(rawSide, "SHORT")) {
		side = "sell"
	}
	var trig any = this.SafeStringUpper(order, "trigger_type")
	var typ any = nil
	if IsTrue(IsEqual(trig, "MARKET")) {
		typ = "market"
	} else if IsTrue(IsEqual(trig, "LIMIT")) {
		typ = "limit"
	}
	var ts any = this.Parse8601(this.SafeString(order, "created_at"))
	if IsTrue(IsEqual(ts, nil)) {
		ts = this.Milliseconds()
	}
	var status any = this.ParseOrderStatus(this.SafeStringLower(order, "status"))
	var sym any = GetValue(market, "symbol")
	return this.SafeOrder(map[string]any{
		"info":                order,
		"id":                  oid,
		"clientOrderId":       nil,
		"timestamp":           ts,
		"datetime":            this.Iso8601(ts),
		"lastTradeTimestamp":  nil,
		"symbol":              sym,
		"type":                typ,
		"timeInForce":         nil,
		"postOnly":            nil,
		"side":                side,
		"price":               this.SafeNumber2(order, "price", "order_price"),
		"stopPrice":           nil,
		"triggerPrice":        nil,
		"amount":              this.SafeNumber2(order, "quantity", "amount"),
		"cost":                nil,
		"average":             nil,
		"filled":              nil,
		"remaining":           nil,
		"status":              status,
		"fee":                 nil,
		"trades":              []any{},
		"fees":                []any{},
		"lastUpdateTimestamp": nil,
		"reduceOnly":          this.SafeBool(order, "reduce_only"),
	}, market)
}

