func (this *MudrexCore) ParseTrade(trade any, optionalArgs ...any) any {
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var ms any = this.SafeString(trade, "symbol")
	market = this.SafeMarket(ms, market)
	var symbol any = GetValue(market, "symbol")
	var ts any = this.Parse8601(this.SafeString(trade, "created_at"))
	if IsTrue(IsEqual(ts, nil)) {
		ts = this.SafeInteger(trade, "time")
	}
	var side any = this.SafeStringLower2(trade, "side", "order_type")
	var tradeSide any = nil
	if IsTrue(IsTrue(IsEqual(side, "buy")) || IsTrue(IsEqual(side, "long"))) {
		tradeSide = "buy"
	} else if IsTrue(IsTrue(IsEqual(side, "sell")) || IsTrue(IsEqual(side, "short"))) {
		tradeSide = "sell"
	}
	var feeType any = this.SafeStringUpper(trade, "fee_type")
	var takerOrMaker any = nil
	if IsTrue(IsEqual(feeType, "TRANSACTION")) {
		takerOrMaker = "taker"
	} else if IsTrue(IsEqual(feeType, "REBATE")) {
		takerOrMaker = "maker"
	}
	var fee any = nil
	var feeCost any = this.SafeNumber(trade, "fee_amount")
	if IsTrue(!IsEqual(feeCost, nil)) {
		fee = map[string]any{
			"cost":     feeCost,
			"currency": this.SafeString(trade, "trade_currency"),
		}
	}
	return this.SafeTrade(map[string]any{
		"info":         trade,
		"timestamp":    ts,
		"datetime":     this.Iso8601(ts),
		"symbol":       symbol,
		"id":           this.SafeString2(trade, "execId", "id"),
		"order":        this.SafeString(trade, "order_id"),
		"type":         this.SafeStringLower(trade, "trigger_type"),
		"side":         tradeSide,
		"takerOrMaker": takerOrMaker,
		"price":        this.SafeNumber(trade, "price"),
		"amount":       this.SafeNumber2(trade, "size", "quantity"),
		"cost":         this.SafeNumber(trade, "transaction_amount"),
		"fee":          fee,
	}, market)
}

/**
 * @method
 * @name mudrex#transfer
 * @description transfer currency internally between wallets on the same account
 * @see https://docs.trade.mudrex.com/docs
 * @param {string} code unified currency code
 * @param {float} amount amount to transfer
 * @param {string} fromAccount 'spot' or 'futures'
 * @param {string} toAccount 'spot' or 'futures'
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} a [transfer structure](https://docs.ccxt.com/#/?id=transfer-structure)
 */
func (this *MudrexCore) Transfer(code any, amount any, fromAccount any, toAccount any, optionalArgs ...any) <-chan any {
	ch := make(chan any)
	go func() any {
		defer close(ch)
		defer ReturnPanicError(ch)
		params := GetArg(optionalArgs, 0, map[string]any{})
		_ = params
		var mp any = map[string]any{
			"spot":    "SPOT",
			"SPOT":    "SPOT",
			"futures": "FUTURES",
			"future":  "FUTURES",
			"FUTURES": "FUTURES",
		}
		var fw any = this.SafeString(mp, fromAccount, ToUpper(fromAccount))
		var tw any = this.SafeString(mp, toAccount, ToUpper(toAccount))
		var body any = map[string]any{
			"from_wallet_type": fw,
			"to_wallet_type":   tw,
			"amount":           this.NumberToString(amount),
		}
		var useInr any = false
		if IsTrue(IsEqual(code, "INR")) {
			useInr = true
		} else {
			// default USDT does not use the inr path
			var tradeCurrency any = this.SafeString2(params, "trade_currency", "tradeCurrency")
			if IsTrue(IsEqual(tradeCurrency, "INR")) {
				useInr = true
			}
		}
		var response any = nil
		if IsTrue(useInr) {

			response = (<-this.PrivatePostFuturesTransfersInr(this.Extend(body, params)))
			PanicOnError(response)
		} else {

			response = (<-this.PrivatePostWalletFuturesTransfer(this.Extend(body, params)))
			PanicOnError(response)
		}
		var data any = this.SafeDict(response, "data", response)

		ch <- map[string]any{
			"info":        response,
			"id":          this.SafeString(data, "id"),
			"timestamp":   nil,
			"datetime":    nil,
			"currency":    code,
			"amount":      amount,
			"fromAccount": fw,
			"toAccount":   tw,
			"status":      "ok",
		}
		return nil

	}()
	return ch
}

func (this *MudrexCore) Init(userConfig map[string]any) {
	this.Exchange = Exchange{}
	this.Exchange.DerivedExchange = this
	this.Exchange.InitParent(userConfig, this.Describe().(map[string]any), this)
}
